//! `baton-put` — upload local files into iRODS as data objects.
//!
//! Each input line names the iRODS destination via `collection` +
//! `data_object` and the local source via `directory` (the local
//! file is `<directory>/<data_object>`; same name on both sides for
//! now — the per-record `file` field for renamed local paths is
//! tracked in issue #30).
//!
//! Two optional digest flags mirror upstream baton's surface:
//!
//! - `--checksum`: after the upload completes, ask iRODS to record a
//!   server-side digest and emit it on the output `checksum` field.
//! - `--verify`: in addition to the server-side digest, hash the
//!   bytes client-side as they stream up and compare. Mismatch is an
//!   in-band per-input error; the bytes are left on the server (no
//!   auto-clean — matches upstream).
//!
//! `--checksum` and `--verify` are mutually exclusive at the CLI to
//! match upstream's documented surface — passing `--verify` alone
//! gives both digest behaviours, so passing both has no useful
//! meaning.

use std::io::{BufRead, Write};

use anyhow::{Context, Result};
use baton_rs::operations::put::{self, PutOptions};
use baton_rs::{RodsConnection, Target};
use clap::Parser;
use tracing_subscriber::EnvFilter;

#[derive(Parser, Debug)]
#[command(name = "baton-put", about = "Upload local files into iRODS")]
struct Args {
    /// Compute and record a server-side checksum for each uploaded
    /// data object; populated on the output `checksum` field.
    #[arg(long, conflicts_with = "verify")]
    checksum: bool,

    /// Compute MD5 client-side as bytes are streamed up, compare
    /// against iRODS's digest after close, and surface any mismatch
    /// as a per-input error. Implies `--checksum` on the output (a
    /// successful verify also populates the digest field).
    #[arg(long)]
    verify: bool,

    /// Verbose logging (DEBUG level).
    #[arg(short, long, conflicts_with = "silent")]
    verbose: bool,

    /// Silent logging (ERROR level only).
    #[arg(long)]
    silent: bool,
}

impl Args {
    fn to_options(&self) -> PutOptions {
        PutOptions {
            checksum: self.checksum,
            verify: self.verify,
        }
    }

    fn log_level(&self) -> &'static str {
        if self.silent {
            "error"
        } else if self.verbose {
            "debug"
        } else {
            "info"
        }
    }
}

fn init_tracing(args: &Args) {
    let filter = EnvFilter::try_from_default_env()
        .unwrap_or_else(|_| EnvFilter::new(args.log_level()));
    tracing_subscriber::fmt()
        .with_env_filter(filter)
        .with_writer(std::io::stderr)
        .init();
}

fn main() -> Result<()> {
    let args = Args::parse();
    init_tracing(&args);

    let opts = args.to_options();

    let mut conn = RodsConnection::connect_from_env().context("connecting to iRODS")?;
    conn.login_from_auth_file().context("authenticating")?;

    let stdin = std::io::stdin();
    let stdout = std::io::stdout();
    let mut out = stdout.lock();

    for line in stdin.lock().lines() {
        let line = line.context("reading stdin")?;
        if line.trim().is_empty() {
            continue;
        }

        let target: Target =
            serde_json::from_str(&line).context("parsing input line as a Target")?;

        // iRODS-side failures per input are annotated in-band and the
        // stream keeps going. Parse / IO errors above are still
        // fail-fast — we can't annotate something we couldn't parse.
        let output = put::put_one_annotated(&mut conn, target, &opts);

        serde_json::to_writer(&mut out, &output).context("writing output line")?;
        writeln!(&mut out).context("writing newline")?;
    }

    Ok(())
}
